const input = $input.first()?.json ?? {};

const primaryModel = String(input.model ?? 'gpt-5').trim();
const fallbackModel = String(input.fallback_model ?? 'gpt-5').trim();
const model = primaryModel || 'gpt-5';
const cliproxyBaseUrl = String(input.cliproxy_base_url ?? '').replace(/\/$/, '');
const cliproxyClientKey = String(input.cliproxy_client_key ?? '');
const openaiModel = String(input.openai_model ?? 'gpt-5').trim() || 'gpt-5';
const scoreThresholdRaw = Number(input.qc_score_warning_threshold ?? 7);
const qcScoreWarningThreshold = Number.isFinite(scoreThresholdRaw)
  ? Math.min(10, Math.max(0, Math.floor(scoreThresholdRaw)))
  : 7;
const reviewerWaitTimeoutSecondsRaw = Number(input.reviewer_wait_timeout_seconds ?? 900);
const reviewerWaitTimeoutSeconds = Number.isFinite(reviewerWaitTimeoutSecondsRaw) && reviewerWaitTimeoutSecondsRaw > 10
  ? Math.floor(reviewerWaitTimeoutSecondsRaw)
  : 900;
const userInput = String(input.user_input ?? '').trim();
const masterPromptTemplate = String(input.master_prompt_template ?? '').trim();
const maxTurnsRaw = Number(input.max_turns ?? 8);
const maxTurns = Number.isFinite(maxTurnsRaw) && maxTurnsRaw > 0
  ? Math.floor(maxTurnsRaw)
  : 8;
const requestHelper =
  helpers?.httpRequest ??
  (typeof $helpers !== 'undefined' ? $helpers?.httpRequest : undefined);

const telegramBotToken = String(input.telegram_bot_token ?? '').trim();
const telegramChatId = String(input.chat_id ?? input.telegram_chat_id ?? input.message?.chat?.id ?? '').trim();
const startSource = String(input.start_source ?? '').trim();
const startProgressEstimateMinutes = 2;

function baseOutput(overrides = {}) {
  return {
    ...input,
    message: '',
    full_review: '',
    turn_count: 0,
    stop_reason: 'completed',
    model,
    fallback_model: fallbackModel || null,
    fallback_used: false,
    user_input: userInput,
    cliproxy_base_url: cliproxyBaseUrl,
    cliproxy_client_key: cliproxyClientKey,
    openai_model: openaiModel,
    qc_score_warning_threshold: qcScoreWarningThreshold,
    reviewer_wait_timeout_seconds: reviewerWaitTimeoutSeconds,
    ...overrides,
  };
}

function detectControlTag(value) {
  const text = String(value ?? '').replace(/\r\n/g, '\n');
  const lines = text.split('\n');

  let cursor = 0;
  let foundTag = null;

  for (const line of lines) {
    const markerMatch = line.match(/^\s*-\s*(CONTINUE|END)\s*-\s*$/i);
    if (markerMatch) {
      const markerOffset = line.search(/-/);
      const markerStart = cursor + (markerOffset >= 0 ? markerOffset : 0);
      const markerEnd = cursor + line.length;
      foundTag = {
        type: markerMatch[1].toLowerCase(),
        start: markerStart,
        end: markerEnd,
      };
    }

    cursor += line.length + 1;
  }

  return foundTag;
}

function stripControlTag(value, controlTag, options = {}) {
  const text = String(value ?? '').replace(/\r\n/g, '\n').trimEnd();
  if (!controlTag) {
    return text;
  }

  if (controlTag.type === 'end' && options.keepEndTag === true) {
    return text.slice(0, controlTag.end).trimEnd();
  }

  return text.slice(0, controlTag.start).trimEnd();
}

function shouldFallbackForCapacity(errorMessage) {
  const text = String(errorMessage ?? '');
  return /429|RESOURCE_EXHAUSTED|MODEL_CAPACITY_EXHAUSTED|No capacity available|cooling down/i.test(text);
}

function buildMasterPrompt(template, bookInput) {
  return String(template ?? '').replaceAll('{{USER_INPUT}}', String(bookInput ?? ''));
}

function formatStartProgressText(elapsedSecondsInput = 0) {
  const elapsedSeconds = Math.max(0, Math.floor(Number(elapsedSecondsInput) || 0));
  const elapsedMinutes = Math.floor(elapsedSeconds / 60);
  const remainingSeconds = elapsedSeconds % 60;
  const elapsedLabel = elapsedMinutes > 0
    ? (elapsedMinutes + ' phut ' + String(remainingSeconds).padStart(2, '0') + ' giay')
    : (remainingSeconds + ' giay');
  return 'Dang tao noi dung... (da cho ' + elapsedLabel + ' / du kien ' + startProgressEstimateMinutes + ' phut)';
}

async function editStartProgressMessage(messageId, text) {
  if (!telegramBotToken || !telegramChatId || typeof requestHelper !== 'function') {
    return false;
  }

  const normalizedMessageId = Number(messageId);
  const normalizedText = String(text ?? '').trim();
  if (!Number.isFinite(normalizedMessageId) || normalizedMessageId <= 0 || !normalizedText) {
    return false;
  }

  try {
    await requestHelper({
      method: 'POST',
      url: 'https://api.telegram.org/bot' + telegramBotToken + '/editMessageText',
      body: {
        chat_id: telegramChatId,
        message_id: Math.floor(normalizedMessageId),
        text: normalizedText,
        disable_web_page_preview: true,
      },
      json: true,
      timeout: 15000,
    });
    return true;
  } catch (_) {
    return false;
  }
}

async function deleteStartProgressMessage(messageId) {
  if (!telegramBotToken || !telegramChatId || typeof requestHelper !== 'function') {
    return false;
  }

  const normalizedMessageId = Number(messageId);
  if (!Number.isFinite(normalizedMessageId) || normalizedMessageId <= 0) {
    return false;
  }

  try {
    await requestHelper({
      method: 'POST',
      url: 'https://api.telegram.org/bot' + telegramBotToken + '/deleteMessage',
      body: {
        chat_id: telegramChatId,
        message_id: Math.floor(normalizedMessageId),
      },
      json: true,
      timeout: 15000,
    });
    return true;
  } catch (_) {
    return false;
  }
}

async function sendStartProgressMessage() {
  if (startSource !== 'telegram_command' || !telegramBotToken || !telegramChatId || typeof requestHelper !== 'function') {
    return null;
  }

  try {
    const response = await requestHelper({
      method: 'POST',
      url: 'https://api.telegram.org/bot' + telegramBotToken + '/sendMessage',
      body: {
        chat_id: telegramChatId,
        text: formatStartProgressText(0),
      },
      json: true,
      timeout: 15000,
    });

    const messageId = Number(response?.result?.message_id ?? NaN);
    return Number.isFinite(messageId) ? Math.floor(messageId) : null;
  } catch (_) {
    return null;
  }
}

if (!userInput) {
  return [{
    json: baseOutput({
      message: 'Vui lòng nhập tên sách và tác giả trong chat. Ví dụ: Sách Nhà Giả Kim của tác giả Paulo Coelho.',
    }),
  }];
}

if (!cliproxyBaseUrl || !cliproxyClientKey) {
  return [{
    json: baseOutput({
      message: 'Thiếu cấu hình CLIProxy (base URL hoặc client key).',
      stop_reason: 'api_error',
    }),
  }];
}

if (!masterPromptTemplate) {
  return [{
    json: baseOutput({
      message: 'Thiếu master prompt template (field `master_prompt_template`).',
      stop_reason: 'api_error',
    }),
  }];
}

if (typeof requestHelper !== 'function') {
  return [{
    json: baseOutput({
      message: 'Thiếu helper HTTP trong Code node runtime (cần `helpers.httpRequest`).',
      stop_reason: 'api_error',
    }),
  }];
}

const startProgressMessageId = await sendStartProgressMessage();
const startProgressTickMs = 3000;
let startProgressTimerId = null;
if (Number.isFinite(Number(startProgressMessageId)) && Number(startProgressMessageId) > 0) {
  let inFlightUpdate = false;
  const startedAtMs = Date.now();

  const tickProgress = () => {
    const elapsedSeconds = Math.floor((Date.now() - startedAtMs) / 1000);
    if (inFlightUpdate) {
      startProgressTimerId = setTimeout(tickProgress, startProgressTickMs);
      return;
    }

    inFlightUpdate = true;
    void editStartProgressMessage(
      startProgressMessageId,
      formatStartProgressText(elapsedSeconds),
    ).finally(() => {
      inFlightUpdate = false;
      startProgressTimerId = setTimeout(tickProgress, startProgressTickMs);
    });
  };

  startProgressTimerId = setTimeout(tickProgress, startProgressTickMs);
}

const masterPrompt = buildMasterPrompt(masterPromptTemplate, userInput);
const messages = [{ role: 'user', content: masterPrompt }];
const chunks = [];

let stopReason = 'completed';
let apiError = '';
let turnCount = 0;
let activeModel = model;
let fallbackUsed = false;

for (let turn = 1; turn <= maxTurns; turn += 1) {
  try {
    const candidateModels =
      activeModel === primaryModel &&
      fallbackModel &&
      fallbackModel !== primaryModel
        ? [primaryModel, fallbackModel]
        : [activeModel];

    let response;
    let lastError;
    for (let idx = 0; idx < candidateModels.length; idx += 1) {
      const candidateModel = candidateModels[idx];
      try {
        response = await requestHelper({
          method: 'POST',
          url: cliproxyBaseUrl + '/v1/chat/completions',
          headers: {
            Authorization: 'Bearer ' + cliproxyClientKey,
          },
          body: {
            model: candidateModel,
            messages,
            stream: false,
          },
          json: true,
          timeout: 240000,
        });
        if (candidateModel !== activeModel) {
          fallbackUsed = true;
        }
        activeModel = candidateModel;
        break;
      } catch (error) {
        lastError = error;
        const errorText = error?.message ? String(error.message) : String(error);
        const canTryFallback =
          candidateModel === primaryModel &&
          fallbackModel &&
          fallbackModel !== primaryModel &&
          shouldFallbackForCapacity(errorText);
        if (canTryFallback) {
          continue;
        }
        throw error;
      }
    }

    if (!response) {
      throw (lastError ?? new Error('Không nhận được response từ model.'));
    }

    turnCount = turn;

    const chunk = String(response?.choices?.[0]?.message?.content ?? '').trim();
    if (!chunk) {
      break;
    }

    const controlTag = detectControlTag(chunk);
    chunks.push({
      content: chunk,
      controlTag,
    });
    messages.push({ role: 'assistant', content: chunk });

    if (controlTag?.type === 'continue') {
      if (turn >= maxTurns) {
        stopReason = 'max_turns';
        break;
      }

      messages.push({ role: 'user', content: 'Continue' });
      continue;
    }

    if (controlTag?.type === 'end') {
      break;
    }

    break;
  } catch (error) {
    stopReason = 'api_error';
    apiError = error?.message ? String(error.message) : String(error);
    break;
  }
}

const mergedChunks = chunks
  .map((chunk, index) => {
    const isLast = index === chunks.length - 1;
    const keepEndTag = isLast && chunk.controlTag?.type === 'end';
    return stripControlTag(chunk.content, chunk.controlTag, { keepEndTag });
  })
  .filter((chunk) => chunk !== '');

const fullReview = mergedChunks.join('\n\n').trim();
let message = fullReview;

if (stopReason === 'max_turns') {
  const note = '[Lưu ý: Đã đạt giới hạn ' + maxTurns + ' lượt gọi "Continue".]';
  message = fullReview ? fullReview + '\n\n' + note : note;
} else if (stopReason === 'api_error') {
  const note = apiError
    ? '[Lỗi gọi model (' + activeModel + '): ' + apiError + ']'
    : '[Lỗi gọi model: Không rõ nguyên nhân.]';
  message = fullReview ? fullReview + '\n\n' + note : note;
}

if (!message) {
  message = 'Không nhận được nội dung từ model.';
}

if (startProgressTimerId) {
  clearTimeout(startProgressTimerId);
  startProgressTimerId = null;
}
if (Number.isFinite(Number(startProgressMessageId)) && Number(startProgressMessageId) > 0) {
  await deleteStartProgressMessage(startProgressMessageId);
}

return [{
  json: baseOutput({
    message,
    full_review: fullReview,
    turn_count: turnCount,
    stop_reason: stopReason,
    model: activeModel,
    fallback_used: fallbackUsed,
    start_progress_message_id: startProgressMessageId,
  }),
}];

const input = $json ?? {};

function normalizeText(value) {
  return String(value ?? '').replace(/\r\n/g, '\n').trim();
}

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function detectTrailingControlTag(text) {
  const match = text.match(/(?:^|\n)\s*-\s*(CONTINUE|END)\s*-\s*$/i);
  if (!match) {
    return null;
  }

  const start = typeof match.index === 'number' ? match.index : text.length - match[0].length;
  return {
    type: match[1].toLowerCase(),
    start,
    end: start + match[0].length,
  };
}

function safeJsonParse(value, fallback = null) {
  try {
    return JSON.parse(String(value ?? ''));
  } catch (_) {
    return fallback;
  }
}

function normalizeHashtags(value) {
  const list = Array.isArray(value)
    ? value
    : String(value ?? '')
      .split(/[\n,]+/)
      .map((item) => item.trim())
      .filter(Boolean);

  const normalized = [];
  for (const item of list) {
    const raw = String(item ?? '').trim();
    if (!raw) continue;
    const tag = '#' + raw.replace(/^#+/, '').replace(/\s+/g, '').toLowerCase();
    if (!tag || normalized.includes(tag)) continue;
    normalized.push(tag);
  }

  return normalized.slice(0, 15);
}

function normalizeMetadata(metadataInput) {
  const source = metadataInput && typeof metadataInput === 'object' ? metadataInput : {};
  const hashtags = normalizeHashtags(source.hashtags);
  return {
    title: safeText(source.title, 'Tiêu đề video'),
    caption: safeText(source.caption, 'Caption video'),
    thumbnail_text: safeText(source.thumbnail_text, 'Thumbnail text'),
    hashtags: hashtags.length > 0 ? hashtags : ['#bookreview', '#selfhelp', '#phattrienbanthan'],
  };
}

function extractMetadataBlock(rawBody) {
  const metadataRegex = /<<<METADATA_JSON>>>\s*([\s\S]*?)\s*<<<END_METADATA_JSON>>>/gi;
  let match;
  let lastMatch = null;

  while ((match = metadataRegex.exec(rawBody)) !== null) {
    lastMatch = {
      start: match.index,
      end: metadataRegex.lastIndex,
      content: String(match[1] ?? '').trim(),
    };
  }

  if (!lastMatch) {
    return {
      reviewBody: rawBody,
      metadata: null,
      metadata_parse_status: 'missing',
      metadata_parse_error: null,
    };
  }

  const parsed = safeJsonParse(lastMatch.content, null);
  if (!parsed || typeof parsed !== 'object') {
    return {
      reviewBody: (rawBody.slice(0, lastMatch.start) + '\n' + rawBody.slice(lastMatch.end)).trim(),
      metadata: null,
      metadata_parse_status: 'invalid_json',
      metadata_parse_error: 'metadata_json_parse_failed',
    };
  }

  return {
    reviewBody: (rawBody.slice(0, lastMatch.start) + '\n' + rawBody.slice(lastMatch.end)).trim(),
    metadata: normalizeMetadata(parsed),
    metadata_parse_status: 'parsed',
    metadata_parse_error: null,
  };
}

function buildFileName(order, id) {
  const orderLabel = String(order).padStart(2, '0');
  const safeId = String(id || 'section')
    .trim()
    .toLowerCase()
    .replace(/[^a-z0-9_]+/g, '_')
    .replace(/^_+|_+$/g, '') || 'section';
  return orderLabel + '_' + safeId + '.txt';
}

function createSessionToken() {
  return Date.now().toString(36) + Math.random().toString(36).slice(2, 10);
}

const rawReview = normalizeText(input.full_review ?? input.message ?? '');
const trailingTag = detectTrailingControlTag(rawReview);
const reviewBeforeTag = trailingTag ? rawReview.slice(0, trailingTag.start).trimEnd() : rawReview;

const extracted = extractMetadataBlock(reviewBeforeTag);
const reviewBody = normalizeText(extracted.reviewBody);

const sectionRegex = /<<<SECTION\|([^|\n>]+)\|([^\n>]+)>>>\s*([\s\S]*?)\s*<<<END_SECTION>>>/g;
const sections = [];
let match;

while ((match = sectionRegex.exec(reviewBody)) !== null) {
  const id = String(match[1] ?? '').trim();
  const title = String(match[2] ?? '').trim();
  const content = String(match[3] ?? '').trim();
  const order = sections.length + 1;

  sections.push({
    order,
    id,
    title,
    content,
    file_name: buildFileName(order, id),
  });
}

let parseStatus = 'parsed';
let parserWarning = '';

if (!reviewBody) {
  parseStatus = 'empty';
  parserWarning = 'No review content to parse.';
} else if (sections.length === 0) {
  parseStatus = 'fallback_single_section';
  parserWarning = 'Cannot find SECTION markers. Returned full review as one section.';
  sections.push({
    order: 1,
    id: 'full_review',
    title: 'Full Review',
    content: reviewBody,
    file_name: '01_full_review.txt',
  });
}

const introSection = sections.find((section) => section.id === 'intro') ?? null;
const outroSection = sections.find((section) => section.id === 'outro') ?? null;
const partSections = sections.filter((section) => /^part_\d{2}$/i.test(section.id));

const metadata = extracted.metadata ?? normalizeMetadata(input.metadata);
const sessionToken = safeText(input.session_token, createSessionToken());
const eventType = safeText(input.event_type, 'init_review');
const source = safeText(input.source, 'main');
const instruction = safeText(input.instruction);

return {
  ...input,
  session_token: sessionToken,
  event_type: eventType,
  source,
  instruction,
  full_review: reviewBody,
  review_sections: sections,
  review_intro: introSection?.content ?? '',
  review_parts: partSections,
  review_outro: outroSection?.content ?? '',
  review_sections_count: sections.length,
  review_control_tag: trailingTag?.type ?? null,
  review_parse_status: parseStatus,
  review_parser_warning: parserWarning || null,
  metadata,
  metadata_parse_status: extracted.metadata_parse_status,
  metadata_parse_error: extracted.metadata_parse_error,
  video_title: safeText(metadata.title),
  video_caption: safeText(metadata.caption),
  video_thumbnail_text: safeText(metadata.thumbnail_text),
  video_hashtags: Array.isArray(metadata.hashtags) ? metadata.hashtags : [],
};

const input = $input.first()?.json ?? {};

function mapActionToEvent(stage, action) {
  const normalizedStage = String(stage ?? '').toLowerCase();
  const mediaStage =
    normalizedStage === 'media_pending' ||
    normalizedStage === 'review_pending' ||
    normalizedStage === 'metadata_pending';

  if (!mediaStage) {
    return '';
  }

  if (action === 'continue') return 'media_continue';
  if (action === 'stop') return 'media_stop';
  return '';
}

function callbackEventType(stageCode, actionCode) {
  const stage =
    stageCode === 'media' ? 'media_pending' :
    stageCode === 'meta' ? 'metadata_pending' :
    'review_pending';

  const action =
    actionCode === 'c' ? 'continue' :
    actionCode === 's' ? 'stop' : '';

  return {
    stage,
    action,
    event_type: mapActionToEvent(stage, action),
  };
}

const callbackData = String(input.callback_query?.data ?? '').trim();
if (!callbackData) {
  // Hanh dong reviewer duoc xu ly qua inline button trong [REVIEW READY].
  return [];
}

const callbackMatch = callbackData.match(/^brv:(media|rvw|meta):(c|s|x):([a-z0-9_-]{8,64})$/i);
if (!callbackMatch) {
  return [];
}

const stageCode = String(callbackMatch[1] ?? '').toLowerCase();
const actionCode = String(callbackMatch[2] ?? '').toLowerCase();
const token = String(callbackMatch[3] ?? '').trim();
const mapped = callbackEventType(stageCode, actionCode);

if (!token || !mapped.event_type) {
  return [];
}

return [{
  json: {
    event_type: mapped.event_type,
    session_token: token,
    instruction: '',
    source: 'telegram',
    router_channel: 'callback_query',
    callback_id: String(input.callback_query?.id ?? '').trim(),
    callback_message_id: Number(input.callback_query?.message?.message_id ?? 0),
    callback_chat_id: String(input.callback_query?.message?.chat?.id ?? '').trim(),
    callback_data: callbackData,
    stage_hint: mapped.stage,
  },
}];

const input = $json ?? {};

const requestHelper =
  helpers?.httpRequest ??
  (typeof $helpers !== 'undefined' ? $helpers?.httpRequest : undefined);

const cliproxyBaseUrl = String(input.cliproxy_base_url ?? '').replace(/\/$/, '');
const cliproxyClientKey = String(input.cliproxy_client_key ?? '').trim();
const openaiModel = String(input.openai_model ?? 'gpt-5').trim() || 'gpt-5';

const n8nApiUrl = String(input.n8n_api_url ?? '').replace(/\/$/, '');
const n8nApiKey = String(input.n8n_api_key ?? '').trim();
const sessionStoreName = String(input.session_store_name ?? 'book_review_sessions').trim() || 'book_review_sessions';

const reviewerTimeoutRaw = Number(input.reviewer_wait_timeout_seconds ?? 900);
const reviewerTimeoutSeconds = Number.isFinite(reviewerTimeoutRaw) && reviewerTimeoutRaw > 30
  ? Math.floor(reviewerTimeoutRaw)
  : 900;

const qcThresholdRaw = Number(input.qc_score_warning_threshold ?? 7);
const qcScoreWarningThreshold = Number.isFinite(qcThresholdRaw)
  ? Math.min(10, Math.max(0, Math.floor(qcThresholdRaw)))
  : 7;

const telegramBotToken = String(input.telegram_bot_token ?? '').trim();
const telegramChatId = String(input.telegram_chat_id ?? '').trim();
const telegramMessageTextLimit = 4000;

const metadataPromptTemplate = String(input.metadata_prompt_template ?? '').trim();

const eventType = String(input.event_type ?? '').trim();
const sessionTokenInput = String(input.session_token ?? '').trim();
const instructionInput = String(input.instruction ?? '').trim();
const sourceInput = String(input.source ?? 'worker').trim();

const REQUIRED_COLUMNS = [
  { name: 'session_token', type: 'string' },
  { name: 'stage', type: 'string' },
  { name: 'deadline_at', type: 'string' },
  { name: 'awaiting_instruction', type: 'string' },
  { name: 'user_input', type: 'string' },
  { name: 'full_review', type: 'string' },
  { name: 'review_intro', type: 'string' },
  { name: 'review_outro', type: 'string' },
  { name: 'qc_json', type: 'string' },
  { name: 'metadata_json', type: 'string' },
  { name: 'review_round', type: 'number' },
  { name: 'metadata_round', type: 'number' },
  { name: 'commands_json', type: 'string' },
  { name: 'stop_reason', type: 'string' },
  { name: 'updated_at', type: 'string' },
  { name: 'payload_json', type: 'string' },
];

const METADATA_FIELDS = ['title', 'caption', 'thumbnail_text', 'hashtags'];

function nowIso() {
  return new Date().toISOString();
}

function addSeconds(iso, seconds) {
  const base = new Date(iso || Date.now());
  const next = new Date(base.getTime() + seconds * 1000);
  return next.toISOString();
}

function asNumber(value, fallback = 0) {
  const num = Number(value);
  return Number.isFinite(num) ? num : fallback;
}

function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function safeJsonParse(value, fallback) {
  try {
    return JSON.parse(String(value ?? ''));
  } catch (_) {
    return fallback;
  }
}

function safeJsonStringify(value, fallback = '{}') {
  try {
    return JSON.stringify(value);
  } catch (_) {
    return fallback;
  }
}

function normalizeDriveContext(source) {
  const input = source && typeof source === 'object' ? source : {};
  return {
    session_folder_id: safeText(input.session_folder_id),
    session_folder_url: safeText(input.session_folder_url),
    session_voice_folder_id: safeText(input.session_voice_folder_id),
    session_voice_folder_url: safeText(input.session_voice_folder_url),
    session_image_folder_id: safeText(input.session_image_folder_id),
    session_image_folder_url: safeText(input.session_image_folder_url),
    session_review_file_id: safeText(input.session_review_file_id),
    session_review_file_url: safeText(input.session_review_file_url),
    session_metadata_file_id: safeText(input.session_metadata_file_id),
    session_metadata_file_url: safeText(input.session_metadata_file_url),
    session_manifest_file_id: safeText(input.session_manifest_file_id),
    session_manifest_file_url: safeText(input.session_manifest_file_url),
    session_sheet_id: safeText(input.session_sheet_id),
    session_sheet_url: safeText(input.session_sheet_url),
  };
}

function mergeDriveContext(baseContext, incomingContext) {
  const base = normalizeDriveContext(baseContext);
  const incoming = normalizeDriveContext(incomingContext);
  const merged = { ...base };

  for (const [key, value] of Object.entries(incoming)) {
    if (safeText(value)) {
      merged[key] = safeText(value);
    }
  }

  return merged;
}

function parseJsonObject(rawText) {
  const raw = String(rawText ?? '').trim();
  if (!raw) return null;

  try {
    return JSON.parse(raw);
  } catch (_) {}

  const fence = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fence) {
    try {
      return JSON.parse(fence[1]);
    } catch (_) {}
  }

  const first = raw.indexOf('{');
  const last = raw.lastIndexOf('}');
  if (first >= 0 && last > first) {
    try {
      return JSON.parse(raw.slice(first, last + 1));
    } catch (_) {}
  }

  return null;
}

function normalizeList(value) {
  if (Array.isArray(value)) {
    return value.map((item) => String(item ?? '').trim()).filter(Boolean);
  }

  if (typeof value === 'string') {
    return value
      .split(/[\n,]+/)
      .map((item) => item.trim())
      .filter(Boolean);
  }

  return [];
}

function normalizeHashtags(value) {
  const tags = normalizeList(value)
    .map((item) => item.replace(/^#*/, '').replace(/\s+/g, ''))
    .filter(Boolean)
    .map((item) => '#' + item.toLowerCase());

  const unique = [];
  for (const tag of tags) {
    if (!unique.includes(tag)) {
      unique.push(tag);
    }
  }

  return unique.slice(0, 15);
}

function stripControlTags(text) {
  const normalized = String(text ?? '').replace(/\r\n/g, '\n').trim();
  return normalized.replace(/(?:\n|^)\s*-\s*(CONTINUE|END)\s*-\s*$/i, '').trim();
}

function normalizeReviewForDisplay(reviewText) {
  const normalized = stripControlTags(reviewText);
  const sectionRegex = /<<<SECTION\|([^|\n>]+)\|([^\n>]+)>>>\s*([\s\S]*?)\s*<<<END_SECTION>>>/g;
  const blocks = [];
  let match;

  while ((match = sectionRegex.exec(normalized)) !== null) {
    const title = safeText(match[2]);
    const content = safeText(match[3]);
    if (!content) continue;
    blocks.push(title ? (title + '\n' + content) : content);
  }

  if (blocks.length > 0) {
    return blocks.join('\n\n').trim();
  }

  return normalized
    .replace(/<<<SECTION\|[^>]+>>>/g, '')
    .replace(/<<<END_SECTION>>>/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function extractSectionText(review, id) {
  const regex = new RegExp('<<<SECTION\\|' + id + '\\|[^>]+>>>\\s*([\\s\\S]*?)\\s*<<<END_SECTION>>>', 'i');
  const match = String(review ?? '').match(regex);
  return match ? String(match[1] ?? '').trim() : '';
}

function ensureKeepOthersInstruction(instruction) {
  const base = safeText(instruction);
  if (!base) return '';

  const keepPattern = /những\s+thứ\s+khác\s+giữ\s+nguyên|nhung\s+thu\s+khac\s+giu\s+nguyen|keep\s+(the\s+)?other\s+fields\s+unchanged/i;
  if (keepPattern.test(base)) {
    return base;
  }

  return base + '. Những thứ khác giữ nguyên.';
}

function detectMetadataTargets(instruction) {
  const text = String(instruction ?? '').toLowerCase();
  const targets = new Set();

  if (!text) {
    return targets;
  }

  if (/(\btitle\b|ti[eê]u\s*đ[eề]\b|tieu\s*de\b)/i.test(text)) {
    targets.add('title');
  }

  if (/(\bcaption\b|ch[uú]\s*th[ií]ch|m[oô]\s*t[aả]\s*ng[aă]n)/i.test(text)) {
    targets.add('caption');
  }

  if (/(\bthumbnail\b|\bthumb\b|thumbnail\s*text|anh\s*bia|ảnh\s*bìa)/i.test(text)) {
    targets.add('thumbnail_text');
  }

  if (/(\bhashtag\b|hash\s*tag|\btags?\b)/i.test(text)) {
    targets.add('hashtags');
  }

  return targets;
}

function defaultMetadataFallback(previousMetadata) {
  if (previousMetadata && typeof previousMetadata === 'object') {
    return {
      title: safeText(previousMetadata.title, 'Tiêu đề video'),
      caption: safeText(previousMetadata.caption, 'Caption video'),
      thumbnail_text: safeText(previousMetadata.thumbnail_text, 'Thumbnail text'),
      hashtags: Array.isArray(previousMetadata.hashtags) && previousMetadata.hashtags.length > 0
        ? previousMetadata.hashtags
        : ['#bookreview', '#selfhelp', '#phattrienbanthan'],
    };
  }

  return {
    title: 'Tiêu đề video',
    caption: 'Caption video',
    thumbnail_text: 'Thumbnail text',
    hashtags: ['#bookreview', '#selfhelp', '#phattrienbanthan'],
  };
}

function normalizeMetadataBundle(metadataInput, fallbackInput = null) {
  const fallback = defaultMetadataFallback(fallbackInput);
  const source = metadataInput && typeof metadataInput === 'object'
    ? metadataInput
    : {};

  const hashtags = normalizeHashtags(source.hashtags);

  return {
    title: safeText(source.title, fallback.title),
    caption: safeText(source.caption, fallback.caption),
    thumbnail_text: safeText(source.thumbnail_text, fallback.thumbnail_text),
    hashtags: hashtags.length > 0 ? hashtags : fallback.hashtags,
  };
}

async function apiRequest(method, path, options = {}) {
  if (typeof requestHelper !== 'function') {
    throw new Error('Missing HTTP helper in Code node runtime.');
  }

  if (!n8nApiUrl || !n8nApiKey) {
    throw new Error('Missing n8n API URL or API key in workflow config.');
  }

  return await requestHelper({
    method,
    url: n8nApiUrl + path,
    headers: {
      'X-N8N-API-KEY': n8nApiKey,
    },
    qs: options.qs,
    body: options.body,
    json: true,
    timeout: 60000,
  });
}

async function ensureDataTable() {
  const list = await apiRequest('GET', '/api/v1/data-tables', {
    qs: { limit: 200 },
  });

  const tables = Array.isArray(list?.data) ? list.data : [];
  const existing = tables.find((table) => String(table?.name ?? '') === sessionStoreName);
  if (existing?.id) {
    return String(existing.id);
  }

  const created = await apiRequest('POST', '/api/v1/data-tables', {
    body: {
      name: sessionStoreName,
      columns: REQUIRED_COLUMNS,
    },
  });

  const id = String(created?.id ?? '').trim();
  if (!id) {
    throw new Error('Failed to create session data table.');
  }

  return id;
}

async function getSessionRow(tableId, sessionToken) {
  if (!sessionToken) return null;

  const rows = await apiRequest('GET', '/api/v1/data-tables/' + tableId + '/rows', {
    qs: {
      limit: 1,
      sortBy: 'updated_at:desc',
      filter: JSON.stringify({
        type: 'and',
        filters: [
          {
            columnName: 'session_token',
            condition: 'eq',
            value: sessionToken,
          },
        ],
      }),
    },
  });

  const data = Array.isArray(rows?.data) ? rows.data : [];
  return data[0] ?? null;
}

function deserializeSession(row) {
  if (!row || typeof row !== 'object') {
    return null;
  }

  const payload = safeJsonParse(row.payload_json, {}) ?? {};
  const payloadDriveContext = payload.drive_context && typeof payload.drive_context === 'object'
    ? payload.drive_context
    : {};

  const qcFromRow = safeJsonParse(row.qc_json, null);
  const metadataFromRow = safeJsonParse(row.metadata_json, null);
  const commandsFromRow = safeJsonParse(row.commands_json, null);

  const session = {
    session_token: safeText(row.session_token, safeText(payload.session_token)),
    stage: safeText(row.stage, safeText(payload.stage, 'review_pending')),
    deadline_at: safeText(row.deadline_at, safeText(payload.deadline_at)),
    awaiting_instruction: String(row.awaiting_instruction ?? payload.awaiting_instruction ?? '') === '1' || payload.awaiting_instruction === true,
    user_input: safeText(row.user_input, safeText(payload.user_input)),
    full_review: safeText(row.full_review, safeText(payload.full_review)),
    review_intro: safeText(row.review_intro, safeText(payload.review_intro)),
    review_outro: safeText(row.review_outro, safeText(payload.review_outro)),
    review_round: asNumber(row.review_round, asNumber(payload.review_round, 0)),
    metadata_round: asNumber(row.metadata_round, asNumber(payload.metadata_round, 0)),
    stop_reason: safeText(row.stop_reason, safeText(payload.stop_reason)),
    updated_at: safeText(row.updated_at, safeText(payload.updated_at, nowIso())),
    turn_count: asNumber(payload.turn_count, 0),
    model: safeText(payload.model, ''),
    fallback_model: safeText(payload.fallback_model, ''),
    fallback_used: Boolean(payload.fallback_used),
    max_turns: asNumber(payload.max_turns, 8),
    openai_model: safeText(payload.openai_model, openaiModel),
    qc_score_warning_threshold: asNumber(payload.qc_score_warning_threshold, qcScoreWarningThreshold),
    reviewer_wait_timeout_seconds: asNumber(payload.reviewer_wait_timeout_seconds, reviewerTimeoutSeconds),
    metadata_error: safeText(payload.metadata_error),
    ...mergeDriveContext(payloadDriveContext, payload),
  };

  session.qc = qcFromRow || payload.qc || null;
  session.metadata = metadataFromRow || payload.metadata || null;
  session.commands = Array.isArray(commandsFromRow)
    ? commandsFromRow
    : Array.isArray(payload.commands)
      ? payload.commands
      : [];

  return session;
}

function bootstrapSessionFromInput(sessionToken) {
  const fullReview = safeText(input.full_review, safeText(input.message));
  const inputDriveContext = normalizeDriveContext(input);
  const metadataFromInput = input.metadata && typeof input.metadata === 'object'
    ? input.metadata
    : null;

  return {
    session_token: sessionToken,
    stage: 'media_pending',
    deadline_at: addSeconds(nowIso(), reviewerTimeoutSeconds),
    awaiting_instruction: false,
    user_input: safeText(input.user_input),
    full_review: fullReview,
    review_intro: safeText(input.review_intro, extractSectionText(fullReview, 'intro')),
    review_outro: safeText(input.review_outro, extractSectionText(fullReview, 'outro')),
    qc: null,
    metadata: metadataFromInput,
    review_round: 0,
    metadata_round: 0,
    commands: [],
    stop_reason: safeText(input.stop_reason),
    updated_at: nowIso(),
    turn_count: asNumber(input.turn_count, 0),
    model: safeText(input.model),
    fallback_model: safeText(input.fallback_model),
    fallback_used: Boolean(input.fallback_used),
    max_turns: asNumber(input.max_turns, 8),
    openai_model: safeText(input.openai_model, openaiModel),
    qc_score_warning_threshold: asNumber(input.qc_score_warning_threshold, qcScoreWarningThreshold),
    reviewer_wait_timeout_seconds: asNumber(input.reviewer_wait_timeout_seconds, reviewerTimeoutSeconds),
    metadata_error: '',
    ...inputDriveContext,
  };
}

function serializeSession(session) {
  const qcJson = safeJsonStringify(session.qc ?? {}, '{}');
  const metadataJson = safeJsonStringify(session.metadata ?? {}, '{}');
  const commands = Array.isArray(session.commands) ? session.commands.slice(-200) : [];
  const commandsJson = safeJsonStringify(commands, '[]');

  const payload = {
    session_token: session.session_token,
    stage: session.stage,
    deadline_at: session.deadline_at,
    awaiting_instruction: session.awaiting_instruction === true,
    user_input: session.user_input,
    full_review: session.full_review,
    review_intro: session.review_intro,
    review_outro: session.review_outro,
    review_round: asNumber(session.review_round, 0),
    metadata_round: asNumber(session.metadata_round, 0),
    stop_reason: session.stop_reason,
    updated_at: session.updated_at,
    turn_count: asNumber(session.turn_count, 0),
    model: session.model,
    fallback_model: session.fallback_model,
    fallback_used: Boolean(session.fallback_used),
    max_turns: asNumber(session.max_turns, 8),
    openai_model: session.openai_model,
    qc_score_warning_threshold: asNumber(session.qc_score_warning_threshold, qcScoreWarningThreshold),
    reviewer_wait_timeout_seconds: asNumber(session.reviewer_wait_timeout_seconds, reviewerTimeoutSeconds),
    metadata_error: safeText(session.metadata_error),
    session_folder_id: safeText(session.session_folder_id),
    session_folder_url: safeText(session.session_folder_url),
    session_voice_folder_id: safeText(session.session_voice_folder_id),
    session_voice_folder_url: safeText(session.session_voice_folder_url),
    session_image_folder_id: safeText(session.session_image_folder_id),
    session_image_folder_url: safeText(session.session_image_folder_url),
    session_review_file_id: safeText(session.session_review_file_id),
    session_review_file_url: safeText(session.session_review_file_url),
    session_metadata_file_id: safeText(session.session_metadata_file_id),
    session_metadata_file_url: safeText(session.session_metadata_file_url),
    session_manifest_file_id: safeText(session.session_manifest_file_id),
    session_manifest_file_url: safeText(session.session_manifest_file_url),
    session_sheet_id: safeText(session.session_sheet_id),
    session_sheet_url: safeText(session.session_sheet_url),
    drive_context: normalizeDriveContext(session),
    qc: session.qc ?? null,
    metadata: session.metadata ?? null,
    commands,
  };

  return {
    session_token: session.session_token,
    stage: safeText(session.stage, 'review_pending'),
    deadline_at: safeText(session.deadline_at),
    awaiting_instruction: session.awaiting_instruction === true ? '1' : '',
    user_input: safeText(session.user_input),
    full_review: safeText(session.full_review),
    review_intro: safeText(session.review_intro),
    review_outro: safeText(session.review_outro),
    qc_json: qcJson,
    metadata_json: metadataJson,
    review_round: asNumber(session.review_round, 0),
    metadata_round: asNumber(session.metadata_round, 0),
    commands_json: commandsJson,
    stop_reason: safeText(session.stop_reason),
    updated_at: safeText(session.updated_at, nowIso()),
    payload_json: safeJsonStringify(payload, '{}'),
  };
}

async function saveSession(tableId, session) {
  const rowData = serializeSession(session);

  await apiRequest('POST', '/api/v1/data-tables/' + tableId + '/rows/upsert', {
    body: {
      filter: {
        type: 'and',
        filters: [
          {
            columnName: 'session_token',
            condition: 'eq',
            value: rowData.session_token,
          },
        ],
      },
      data: rowData,
      returnData: false,
    },
  });
}

function appendCommand(session, command) {
  if (!Array.isArray(session.commands)) {
    session.commands = [];
  }

  session.commands.push({
    ts: nowIso(),
    source: sourceInput,
    event_type: eventType,
    ...command,
  });

  if (session.commands.length > 400) {
    session.commands = session.commands.slice(-400);
  }
}

async function callOpenAI(messages, options = {}) {
  if (!cliproxyBaseUrl || !cliproxyClientKey || typeof requestHelper !== 'function') {
    throw new Error('Missing CLIProxy/OpenAI configuration or HTTP helper.');
  }

  const body = {
    model: openaiModel,
    messages,
    stream: false,
  };

  if (options.jsonObject === true) {
    body.response_format = { type: 'json_object' };
  }

  return await requestHelper({
    method: 'POST',
    url: cliproxyBaseUrl + '/v1/chat/completions',
    headers: {
      Authorization: 'Bearer ' + cliproxyClientKey,
    },
    body,
    json: true,
    timeout: Number(options.timeoutMs ?? 180000),
  });
}

async function generateMetadataBundle(session, instruction, previousMetadata) {
  const reviewerInstruction = safeText(instruction);
  const adjustedInstruction = ensureKeepOthersInstruction(reviewerInstruction);
  const requestedTargets = detectMetadataTargets(adjustedInstruction);

  const promptPayload = {
    task: previousMetadata
      ? 'Refine existing metadata for a Vietnamese book-review video.'
      : 'Generate metadata for a Vietnamese book-review video.',
    requirements: {
      output: 'json_only',
      fields: ['title', 'caption', 'thumbnail_text', 'hashtags'],
      style: 'high-retention, concrete, non-clickbait',
      language: 'vi',
      keep_unmentioned_fields: true,
      never_output_fields: ['youtube_description_long', 'description', 'video_description'],
    },
    request: safeText(session.user_input),
    reviewer_instruction: adjustedInstruction,
    previous_metadata: previousMetadata ?? null,
    review_excerpt: safeText(normalizeReviewForDisplay(session.full_review)),
  };

  const systemPrompt = safeText(
    metadataPromptTemplate,
    'You are a short-video growth strategist. Return JSON only with exactly these keys: title, caption, thumbnail_text, hashtags.'
  );

  const response = await callOpenAI([
    {
      role: 'system',
      content: systemPrompt,
    },
    {
      role: 'user',
      content: JSON.stringify(promptPayload),
    },
  ], { jsonObject: true });

  const content = String(response?.choices?.[0]?.message?.content ?? '').trim();
  const parsed = parseJsonObject(content);
  if (!parsed || typeof parsed !== 'object') {
    throw new Error('Metadata response is not valid JSON object.');
  }

  const resolved = {
    title: safeText(parsed.title, previousMetadata?.title || 'Tiêu đề video'),
    caption: safeText(parsed.caption, previousMetadata?.caption || 'Caption video'),
    thumbnail_text: safeText(parsed.thumbnail_text, previousMetadata?.thumbnail_text || 'Thumbnail text'),
    hashtags: normalizeHashtags(parsed.hashtags),
  };

  if (resolved.hashtags.length === 0) {
    resolved.hashtags = Array.isArray(previousMetadata?.hashtags) && previousMetadata.hashtags.length > 0
      ? previousMetadata.hashtags
      : ['#bookreview', '#selfhelp', '#phattrienbanthan'];
  }

  const hasSelectiveInstruction =
    Boolean(previousMetadata) &&
    adjustedInstruction.length > 0 &&
    requestedTargets.size > 0 &&
    requestedTargets.size < METADATA_FIELDS.length;

  if (hasSelectiveInstruction) {
    if (!requestedTargets.has('title')) {
      resolved.title = safeText(previousMetadata?.title, resolved.title);
    }
    if (!requestedTargets.has('caption')) {
      resolved.caption = safeText(previousMetadata?.caption, resolved.caption);
    }
    if (!requestedTargets.has('thumbnail_text')) {
      resolved.thumbnail_text = safeText(previousMetadata?.thumbnail_text, resolved.thumbnail_text);
    }
    if (!requestedTargets.has('hashtags')) {
      resolved.hashtags = Array.isArray(previousMetadata?.hashtags) && previousMetadata.hashtags.length > 0
        ? previousMetadata.hashtags
        : resolved.hashtags;
    }
  }

  return resolved;
}

async function telegramApi(method, params = {}, useGet = false) {
  if (!telegramBotToken || typeof requestHelper !== 'function') {
    return null;
  }

  return await requestHelper({
    method: useGet ? 'GET' : 'POST',
    url: 'https://api.telegram.org/bot' + telegramBotToken + '/' + method,
    qs: useGet ? params : undefined,
    body: useGet ? undefined : params,
    json: true,
    timeout: 60000,
  });
}

async function answerCallback(callbackId, text) {
  const id = safeText(callbackId);
  if (!id) return;
  const normalizedText = safeText(text).slice(0, 180);
  const payload = {
    callback_query_id: id,
    show_alert: false,
  };
  if (normalizedText) {
    payload.text = normalizedText;
  }

  try {
    await telegramApi('answerCallbackQuery', payload, false);
  } catch (_) {}
}

async function lockCallbackActionMessage(callbackChatId, callbackMessageId, text) {
  const chatId = safeText(callbackChatId);
  const messageId = Number(callbackMessageId);
  if (!chatId || !Number.isFinite(messageId) || messageId <= 0) return;

  try {
    await telegramApi('editMessageReplyMarkup', {
      chat_id: chatId,
      message_id: Math.floor(messageId),
      reply_markup: {
        inline_keyboard: [],
      },
    }, false);
  } catch (_) {}
}

function isPendingReviewerStage(stageValue) {
  const stage = safeText(stageValue).toLowerCase();
  return stage === 'media_pending' || stage === 'review_pending' || stage === 'metadata_pending';
}

function isSessionTimedOut(session) {
  if (!session || !isPendingReviewerStage(session.stage)) {
    return false;
  }

  const deadlineText = safeText(session.deadline_at);
  if (!deadlineText) {
    return false;
  }

  const deadlineMs = Date.parse(deadlineText);
  if (!Number.isFinite(deadlineMs)) {
    return false;
  }

  return Date.now() > deadlineMs;
}

function buildTimeoutActionText(session) {
  const stage = safeText(session?.stage).toLowerCase();
  if (stage === 'media_pending') {
    return 'Da qua thoi gian cho tao media, nhung van tiep tuc xu ly theo yeu cau.';
  }
  if (stage === 'metadata_pending') {
    return 'Da qua thoi gian cho metadata, nhung van tiep tuc xu ly theo yeu cau.';
  }

  return 'Da qua thoi gian cho review, nhung van tiep tuc xu ly theo yeu cau.';
}

function buildSessionNotFoundActionText() {
  return 'Session khong con hieu luc.';
}

function buildActionInfoText(eventType, instructionText) {
  if (eventType === 'review_continue' || eventType === 'metadata_continue' || eventType === 'media_continue') {
    return '';
  }
  if (eventType === 'review_stop' || eventType === 'metadata_stop' || eventType === 'media_stop') {
    return 'Da ghi nhan dung.';
  }

  return 'Da ghi nhan thao tac.';
}

async function sendTelegramMessage(text, inlineKeyboardRows) {
  if (!telegramBotToken || !telegramChatId || typeof requestHelper !== 'function') {
    return null;
  }

  const payload = {
    chat_id: telegramChatId,
    text: String(text ?? '').slice(0, telegramMessageTextLimit),
  };

  if (Array.isArray(inlineKeyboardRows) && inlineKeyboardRows.length > 0) {
    payload.reply_markup = {
      inline_keyboard: inlineKeyboardRows,
    };
  }

  return await telegramApi('sendMessage', payload, false);
}

async function deleteTelegramMessage(messageId, chatIdOverride = '') {
  const chatId = safeText(chatIdOverride, telegramChatId);
  const normalizedMessageId = Number(messageId);
  if (!chatId || !Number.isFinite(normalizedMessageId) || normalizedMessageId <= 0) {
    return false;
  }

  try {
    await telegramApi('deleteMessage', {
      chat_id: chatId,
      message_id: Math.floor(normalizedMessageId),
    }, false);
    return true;
  } catch (_) {
    return false;
  }
}

function formatStepProgressText(stepText, estimatedMinutes, elapsedSecondsInput, prefix = '') {
  const normalizedStepText = safeText(stepText);
  const normalizedPrefix = safeText(prefix);
  const estimate = Math.max(1, Math.floor(Number(estimatedMinutes) || 1));
  const elapsedSeconds = Math.max(0, Math.floor(Number(elapsedSecondsInput) || 0));
  const elapsedMinutes = Math.floor(elapsedSeconds / 60);
  const remainingSeconds = elapsedSeconds % 60;
  const elapsedLabel = elapsedMinutes > 0
    ? (elapsedMinutes + ' phut ' + String(remainingSeconds).padStart(2, '0') + ' giay')
    : (remainingSeconds + ' giay');
  const core = normalizedStepText + ' (da cho ' + elapsedLabel + ' / du kien ' + estimate + ' phut)';
  return normalizedPrefix ? (normalizedPrefix + '\n' + core) : core;
}

async function editTelegramMessage(messageId, text, chatIdOverride = '') {
  const chatId = safeText(chatIdOverride, telegramChatId);
  const normalizedMessageId = Number(messageId);
  const normalizedText = safeText(text);
  if (!chatId || !Number.isFinite(normalizedMessageId) || normalizedMessageId <= 0 || !normalizedText) {
    return false;
  }

  try {
    await telegramApi('editMessageText', {
      chat_id: chatId,
      message_id: Math.floor(normalizedMessageId),
      text: normalizedText.slice(0, telegramMessageTextLimit),
      disable_web_page_preview: true,
    }, false);
    return true;
  } catch (_) {
    return false;
  }
}

async function sendStepProgressMessage(stepText, estimatedMinutes = 1, options = {}) {
  const normalizedStepText = safeText(stepText);
  if (!normalizedStepText) {
    return null;
  }

  const minutes = Math.max(1, Math.floor(Number(estimatedMinutes) || 1));
  const prefix = safeText(options.prefix);
  const text = formatStepProgressText(normalizedStepText, minutes, 0, prefix);

  try {
    const response = await sendTelegramMessage(text);
    const messageId = Number(response?.result?.message_id);
    const normalizedMessageId = Number.isFinite(messageId) && messageId > 0
      ? Math.floor(messageId)
      : null;
    if (!normalizedMessageId) {
      return null;
    }

    return {
      message_id: normalizedMessageId,
      chat_id: safeText(options.chatId, telegramChatId),
      step_text: normalizedStepText,
      estimated_minutes: minutes,
      prefix,
      started_at_ms: Date.now(),
    };
  } catch (_) {
    return null;
  }
}

async function withStepProgressMessage(stepText, estimatedMinutes, workerFn, options = {}) {
  const progressMessage = await sendStepProgressMessage(stepText, estimatedMinutes, options);
  let timerId = null;

  if (progressMessage?.message_id) {
    let inFlightUpdate = false;
    timerId = setInterval(() => {
      if (inFlightUpdate) {
        return;
      }

      inFlightUpdate = true;
      const elapsedSeconds = Math.floor((Date.now() - Number(progressMessage.started_at_ms || Date.now())) / 1000);
      const updatedText = formatStepProgressText(
        progressMessage.step_text,
        progressMessage.estimated_minutes,
        elapsedSeconds,
        progressMessage.prefix,
      );

      void editTelegramMessage(
        progressMessage.message_id,
        updatedText,
        progressMessage.chat_id,
      ).finally(() => {
        inFlightUpdate = false;
      });
    }, 3000);
  }

  try {
    return await workerFn();
  } finally {
    if (timerId) {
      clearInterval(timerId);
    }
    if (progressMessage?.message_id) {
      await deleteTelegramMessage(progressMessage.message_id, progressMessage.chat_id);
    }
  }
}

