function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function normalizeText(value) {
  return String(value ?? '').replace(/\r\n/g, '\n').trim();
}

function parseReviewSections(reviewText) {
  const content = normalizeText(reviewText);
  if (!content) return [];

  const sectionRegex = /<<<SECTION\|([^|\n>]+)\|([^\n>]+)>>>([\s\S]*?)<<<END_SECTION>>>/g;
  const sections = [];
  let match;

  while ((match = sectionRegex.exec(content)) !== null) {
    const partName = safeText(match[1]).toLowerCase() || 'part_unknown';
    const sectionText = normalizeText(match[3]);
    if (!sectionText) continue;
    sections.push({
      partName,
      text: sectionText,
    });
  }

  if (sections.length > 0) {
    return sections;
  }

  return [{
    partName: 'full_review',
    text: content,
  }];
}

function splitSentences(text) {
  const normalized = normalizeText(text)
    .replace(/\n+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

  if (!normalized) {
    return [];
  }

  const matches = normalized.match(/[^.!?…]+[.!?…]+|[^.!?…]+$/g) ?? [];
  const sentences = matches
    .map((item) => item.trim())
    .filter(Boolean);

  return sentences.length > 0 ? sentences : [normalized];
}

function buildChunks(sections, maxSentencesPerChunk = 3) {
  const chunks = [];
  let globalOrder = 0;

  for (const section of sections) {
    const partName = safeText(section.partName, 'part_unknown');
    const sentences = splitSentences(section.text);

    if (sentences.length === 0) {
      continue;
    }

    let localIndex = 0;
    for (let cursor = 0; cursor < sentences.length; cursor += maxSentencesPerChunk) {
      localIndex += 1;
      const block = sentences.slice(cursor, cursor + maxSentencesPerChunk);
      const text = block.join(' ').trim();
      if (!text) continue;

      const chunkKey = partName + ':' + localIndex;
      globalOrder += 1;
      chunks.push({
        order: globalOrder,
        chunk_key: chunkKey,
        partName,
        index: localIndex,
        text,
        sentence_count: block.length,
      });
    }
  }

  return chunks;
}

