function normalizeDuration(value) {
  const number = Number(value);
  if (!Number.isFinite(number) || number < 0) return 0;
  return Math.round(number * 1000) / 1000;
}

function clampInt(value, fallback, min, max) {
  const number = Number(value);
  const normalized = Number.isFinite(number) ? Math.floor(number) : fallback;
  return Math.min(max, Math.max(min, normalized));
}

function computeElapsedSeconds(startedAt, finishedAtIso) {
  const started = new Date(startedAt ?? '');
  const finished = new Date(finishedAtIso ?? '');
  if (Number.isNaN(started.getTime()) || Number.isNaN(finished.getTime())) {
    return 0;
  }

  const elapsed = (finished.getTime() - started.getTime()) / 1000;
  if (!Number.isFinite(elapsed) || elapsed < 0) {
    return 0;
  }

  return Math.round(elapsed * 1000) / 1000;
}

function buildChunkFromItem(item, fallbackIndex) {
