  const text = safeText(item?.text);
  const sentenceCount = clampInt(item?.sentence_count, 0, 0, 3);
  const chunkKey = safeText(item?.chunk_key, partName + ':' + index);

  return {
    partName,
    index,
    text,
    chunk_key: chunkKey,
    sentence_count: sentenceCount,
  };
}

