function safeText(value, fallback = '') {
  const text = String(value ?? '').trim();
  return text || fallback;
}

function asNumber(value, fallback = 0) {
  if (value === null || value === undefined) {
    return fallback;
  }
  const raw = typeof value === 'string' ? value.trim() : String(value);
  if (raw === '') {
    return fallback;
  }
  const num = Number(raw);
  return Number.isFinite(num) ? num : fallback;
}

function clampScore(value, fallback = 6) {
  if (value === null || value === undefined) return fallback;
  const raw = typeof value === 'string' ? value.trim() : String(value);
  if (raw === '') return fallback;
  const num = Number(raw);
  if (!Number.isFinite(num)) return fallback;
  if (num < 0) return 0;
  if (num > 10) return 10;
  return Math.round(num * 10) / 10;
}

function normalizeRisk(value) {
  const risk = String(value ?? '').trim().toLowerCase();
  if (risk === 'low' || risk === 'med' || risk === 'high') return risk;
  return 'med';
}

function normalizeList(value) {
  if (Array.isArray(value)) {
    return value.map((item) => String(item ?? '').trim()).filter(Boolean);
  }
  return String(value ?? '')
    .split(/[\n,]+/)
    .map((item) => item.trim())
    .filter(Boolean);
}

function normalizeFeedback(value, fallback = '') {
  const raw = String(value ?? '').replace(/\s+/g, ' ').trim();
  const text = raw || String(fallback ?? '').replace(/\s+/g, ' ').trim();
  if (!text) return '';

  const words = text.split(/\s+/).filter(Boolean);
  if (words.length <= 200) {
    return text;
  }
  return words.slice(0, 200).join(' ');
}

function normalizeForGenericMatch(value) {
  return String(value ?? '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[^\w\s]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .toLowerCase();
}

function isGenericQcFeedback(value) {
  const normalized = normalizeForGenericMatch(value);
  if (!normalized) return true;
  return (
    normalized === 'chua co feedback qc' ||
    normalized.includes('chua co feedback qc') ||
    normalized.includes('khong co feedback qc') ||
    normalized.includes('no qc feedback')
  );
}

function hasNonEmptyNumber(value) {
  if (value === null || value === undefined) return false;
  const raw = typeof value === 'string' ? value.trim() : String(value);
  if (raw === '') return false;
  return Number.isFinite(Number(raw));
}

function buildScoreWarnings(scores, threshold) {
  const map = {
    Hook: scores.hook_score,
    Clarity: scores.clarity_score,
    Originality: scores.originality_score,
    'Practical value': scores.practical_value_score,
  };

  return Object.entries(map)
    .filter(([, score]) => Number(score) < threshold)
    .map(([label, score]) => label + ' score=' + score + ' < ' + threshold);
}

function parseJsonObject(rawText) {
  const raw = String(rawText ?? '').trim();
  if (!raw) return null;

  try {
    return JSON.parse(raw);
  } catch (_) {}

  const fence = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fence) {
    try {
      return JSON.parse(fence[1]);
    } catch (_) {}
  }

  const first = raw.indexOf('{');
  const last = raw.lastIndexOf('}');
  if (first >= 0 && last > first) {
    try {
      return JSON.parse(raw.slice(first, last + 1));
    } catch (_) {}
  }

  return null;
}

function stripControlTags(text) {
  const normalized = String(text ?? '').replace(/\r\n/g, '\n').trim();
  return normalized.replace(/(?:\n|^)\s*-\s*(CONTINUE|END)\s*-\s*$/i, '').trim();
}

function normalizeReviewForDisplay(reviewText) {
  const normalized = stripControlTags(reviewText);
  const sectionRegex = /<<<SECTION\|([^|\n>]+)\|([^\n>]+)>>>\s*([\s\S]*?)\s*<<<END_SECTION>>>/g;
  const blocks = [];
  let match;

  while ((match = sectionRegex.exec(normalized)) !== null) {
    const title = safeText(match[2]);
    const content = safeText(match[3]);
    if (!content) continue;
    blocks.push(title ? (title + '\n' + content) : content);
  }

  if (blocks.length > 0) {
    return blocks.join('\n\n').trim();
  }

  return normalized
    .replace(/<<<SECTION\|[^>]+>>>/g, '')
    .replace(/<<<END_SECTION>>>/g, '')
    .replace(/\n{3,}/g, '\n\n')
    .trim();
}

function buildMediaButtons(sessionToken) {
  return [[
    { text: 'Tao Media', callback_data: 'brv:media:c:' + sessionToken },
    { text: 'Dung', callback_data: 'brv:media:s:' + sessionToken },
  ]];
}

const shouldSendQcAction = input.should_send_qc_action === true;
const mediaActionEmbedded = input.media_action_embedded === true;
const initialMetadataStatus = mediaActionEmbedded ? 'embedded_in_review_ready' : 'suppressed';

if (!shouldSendQcAction) {
  return {
    ...input,
    qc_action_notify_status: 'skipped',
    metadata_action_notify_status: initialMetadataStatus,
  };
}

const requestHelper =
  helpers?.httpRequest ??
  (typeof $helpers !== 'undefined' ? $helpers?.httpRequest : undefined);

const telegramBotToken = safeText(input.telegram_bot_token);
const telegramChatId = safeText(input.telegram_chat_id);
const sessionToken = safeText(input.session_token);

if (!telegramBotToken || !telegramChatId || !sessionToken || typeof requestHelper !== 'function') {
  return {
    ...input,
    qc_action_notify_status: 'skipped_missing_telegram_config',
  };
}

const cliproxyBaseUrl = safeText(input.cliproxy_base_url).replace(/\/$/, '');
const cliproxyClientKey = safeText(input.cliproxy_client_key);
const openaiModel = safeText(input.openai_model, 'gpt-5');
const qcPromptTemplate = safeText(input.qc_prompt_template, 'You are a strict content QC editor. Return JSON only, no markdown.');
const qcThresholdRaw = Number(input.qc_score_warning_threshold ?? 7);
const qcScoreWarningThreshold = Number.isFinite(qcThresholdRaw)
  ? Math.min(10, Math.max(0, Math.floor(qcThresholdRaw)))
  : 7;

async function sendTelegramMessage(text, inlineKeyboardRows) {
  const payload = {
    chat_id: telegramChatId,
    text: String(text ?? '').slice(0, 4000),
  };

  if (Array.isArray(inlineKeyboardRows) && inlineKeyboardRows.length > 0) {
    payload.reply_markup = {
      inline_keyboard: inlineKeyboardRows,
    };
  }

  await requestHelper({
    method: 'POST',
    url: 'https://api.telegram.org/bot' + telegramBotToken + '/sendMessage',
    body: payload,
    json: true,
    timeout: 60000,
  });
}

async function callOpenAI(messages) {
  if (!cliproxyBaseUrl || !cliproxyClientKey) {
    throw new Error('Missing CLIProxy config for QC.');
  }

  const options = arguments[1] && typeof arguments[1] === 'object' ? arguments[1] : {};
  const useJsonObject = options.useJsonObject !== false;
  const body = {
    model: openaiModel,
    messages,
    stream: false,
  };
  if (useJsonObject) {
    body.response_format = { type: 'json_object' };
  }

  return await requestHelper({
    method: 'POST',
    url: cliproxyBaseUrl + '/v1/chat/completions',
    headers: {
      Authorization: 'Bearer ' + cliproxyClientKey,
    },
    body,
    json: true,
    timeout: 180000,
  });
}

function hasUsableQcObject(source) {
  const raw = source && typeof source === 'object' ? source : {};
  const scalarSignals = [
    raw.hook,
    raw.hook_score,
    raw.clarity,
    raw.clarity_score,
    raw.originality,
    raw.originality_score,
    raw.practical,
    raw.practical_value_score,
    raw.risk,
    raw.risk_level,
    raw.feedback,
  ];

  const hasScalar = scalarSignals.some((value) => {
    if (Number.isFinite(Number(value))) return true;
    return safeText(value) !== '';
  });

  const hasList =
    Array.isArray(raw.qc_issues) && raw.qc_issues.length > 0 ||
    Array.isArray(raw.issues) && raw.issues.length > 0 ||
    Array.isArray(raw.qc_checks) && raw.qc_checks.length > 0;

  const hasScoresObject = raw.scores && typeof raw.scores === 'object';
  return hasScalar || hasList || hasScoresObject;
}

function buildHeuristicFeedback(context) {
  const review = safeText(normalizeReviewForDisplay(context.full_review));
  const hints = [];

  if (review.length > 5000) {
    hints.push('Rut gon 10-20% de nhip doc gon hon, uu tien cau ngan va dong tu manh.');
  }
  if (/phan\\s*\\d+|bai\\s*hoc\\s*\\d+|muc\\s*\\d+/i.test(review)) {
    hints.push('Bo kieu danh so meta (Phan 1/Bai hoc 1), chuyen sang dong ke tu su lien mach.');
  }
  if (!/[\"“”']/.test(review)) {
    hints.push('Them 1-2 trich dan ngan (co nguon ro) de tang do tin cay va cam xuc.');
  }
  if (!/(vi\\s*du|chuyen\\s*that|tinh\\s*huong|doi\\s*song)/i.test(review)) {
    hints.push('Bo sung vi du doi song cu the de tang practical value.');
  }

  if (hints.length === 0) {
    hints.push('Mo bai bang 1 noi dau cu the, giu giong ke chuyen nguoi that, va ket bai bang 1 hanh dong nho co the lam ngay.');
  }

  return normalizeFeedback(hints.join(' '), 'Can them feedback QC cu the.');
}

function normalizeQcPayload(source, options = {}) {
  const raw = source && typeof source === 'object' ? source : {};
  const qcIssues = normalizeList(raw.qc_issues ?? raw.issues);
  const qcChecks = Array.isArray(raw.qc_checks) ? raw.qc_checks : [];

  const hookRaw = raw.hook ?? raw.hook_score ?? raw.scores?.hook;
  const clarityRaw = raw.clarity ?? raw.clarity_score ?? raw.scores?.clarity;
  const originalityRaw = raw.originality ?? raw.originality_score ?? raw.scores?.originality;
  const practicalRaw = raw.practical ?? raw.practical_value_score ?? raw.scores?.practical ?? raw.scores?.practical_value;
  const riskRaw = raw.risk ?? raw.risk_level;

  const derivedIssues = qcIssues.length > 0
    ? qcIssues
    : qcChecks
        .filter((check) => String(check?.status ?? '').toLowerCase() !== 'pass')
        .map((check) => String(check?.note ?? '').trim())
        .filter(Boolean);

  const feedbackFallback = safeText(options.fallbackFeedback, derivedIssues.slice(0, 3).join('; '));
  const qc = {
    qc_checks: qcChecks,
    qc_issues: derivedIssues,
    feedback: normalizeFeedback(raw.feedback, feedbackFallback || 'Can them feedback QC cu the.'),
    hook_score: clampScore(hookRaw, 6),
    clarity_score: clampScore(clarityRaw, 6),
    originality_score: clampScore(originalityRaw, 6),
    practical_value_score: clampScore(practicalRaw, 6),
    risk_level: normalizeRisk(riskRaw),
    score_warnings: [],
    qc_status: safeText(options.qcStatus, 'generated'),
    qc_error: safeText(options.qcError) || null,
  };

  qc.score_warnings = buildScoreWarnings(qc, qcScoreWarningThreshold);
  return qc;
}

function enforceQcQuality(normalizedQc, fallbackFeedback, fallbackErrorCode) {
  const qc = normalizedQc && typeof normalizedQc === 'object' ? normalizedQc : {};
  const safeFallbackFeedback = normalizeFeedback(fallbackFeedback, 'Can them feedback QC cu the.');

  const scoresAreDefault =
    Number(qc.hook_score) === 6 &&
    Number(qc.clarity_score) === 6 &&
    Number(qc.originality_score) === 6 &&
    Number(qc.practical_value_score) === 6;

  const feedbackText = safeText(qc.feedback);
  const feedbackWordCount = feedbackText.split(/\s+/).filter(Boolean).length;
  const feedbackLooksGeneric = isGenericQcFeedback(feedbackText);
  const feedbackTooShort = feedbackWordCount < 8;

  if (feedbackLooksGeneric || (scoresAreDefault && feedbackTooShort)) {
    const existingIssues = Array.isArray(qc.qc_issues) ? qc.qc_issues : [];
    const nextIssues = existingIssues.length > 0 ? existingIssues : ['QC fallback.'];
    return {
      ...qc,
      qc_issues: nextIssues,
      feedback: safeFallbackFeedback,
      qc_status: 'fallback',
      qc_error: safeText(qc.qc_error, fallbackErrorCode),
      score_warnings: buildScoreWarnings({
        hook_score: qc.hook_score,
        clarity_score: qc.clarity_score,
        originality_score: qc.originality_score,
        practical_value_score: qc.practical_value_score,
      }, qcScoreWarningThreshold),
    };
  }

  return qc;
}

async function resolveQcPayload() {
  const existingQc = input.qc && typeof input.qc === 'object'
    ? input.qc
    : {
        hook_score: input.hook_score,
        clarity_score: input.clarity_score,
        originality_score: input.originality_score,
        practical_value_score: input.practical_value_score,
        risk_level: input.risk_level,
        feedback: input.feedback,
        score_warnings: input.score_warnings,
        qc_status: input.qc_status,
      };

  const hasExistingScores =
    hasNonEmptyNumber(existingQc?.hook_score) &&
    hasNonEmptyNumber(existingQc?.clarity_score) &&
    hasNonEmptyNumber(existingQc?.originality_score) &&
    hasNonEmptyNumber(existingQc?.practical_value_score);

  const heuristicFeedback = buildHeuristicFeedback(input);

  if (hasExistingScores) {
    const normalizedExisting = normalizeQcPayload(existingQc, {
      qcStatus: safeText(existingQc?.qc_status, 'generated'),
      qcError: safeText(existingQc?.qc_error),
      fallbackFeedback: heuristicFeedback,
    });
    return enforceQcQuality(normalizedExisting, heuristicFeedback, 'qc_existing_payload_generic');
  }

  const fallbackQc = {
    qc_checks: [],
    qc_issues: ['QC fallback.'],
    feedback: heuristicFeedback,
    hook_score: 6,
    clarity_score: 6,
    originality_score: 6,
    practical_value_score: 6,
    risk_level: 'med',
    score_warnings: [],
    qc_status: 'fallback',
    qc_error: null,
  };

  try {
    const promptPayload = {
      task: 'QC a Vietnamese long-form book review script.',
      policy: {
        quote_policy: 'Only accept direct quote if source certainty is high. Otherwise mark warn.',
        no_rewrite: true,
      },
      input: {
        request: safeText(input.user_input),
        intro_excerpt: safeText(input.review_intro),
        outro_excerpt: safeText(input.review_outro),
        review_excerpt: safeText(normalizeReviewForDisplay(input.full_review)),
      },
      required_json_schema: {
        hook: 0,
        clarity: 0,
        originality: 0,
        practical: 0,
        risk: 'low|med|high',
        feedback: 'string (Vietnamese, actionable, <= 200 words)',
        qc_issues: ['string (optional)'],
      },
    };

    const baseMessages = [
      {
        role: 'system',
        content: qcPromptTemplate,
      },
      {
        role: 'user',
        content: JSON.stringify(promptPayload),
      },
    ];

    const response = await callOpenAI(baseMessages, { useJsonObject: true });

    const content = String(response?.choices?.[0]?.message?.content ?? '').trim();
    let parsed = parseJsonObject(content);
    if (!parsed || typeof parsed !== 'object' || !hasUsableQcObject(parsed)) {
      const retryPromptPayload = {
        ...promptPayload,
        output_rule: 'Tra ve JSON day du key hook,clarity,originality,practical,risk,feedback,qc_issues; feedback bat buoc khong rong.',
      };
      const retryResponse = await callOpenAI([
        {
          role: 'system',
          content: qcPromptTemplate,
        },
        {
          role: 'user',
          content: JSON.stringify(retryPromptPayload),
        },
      ], { useJsonObject: false });

      const retryContent = String(retryResponse?.choices?.[0]?.message?.content ?? '').trim();
      const retryParsed = parseJsonObject(retryContent);
      if (!retryParsed || typeof retryParsed !== 'object' || !hasUsableQcObject(retryParsed)) {
        throw new Error('QC response missing required fields.');
      }
      parsed = retryParsed;
    }

    const normalized = normalizeQcPayload(parsed, {
      qcStatus: 'generated',
      fallbackFeedback: heuristicFeedback,
    });
    return enforceQcQuality(normalized, heuristicFeedback, 'qc_payload_empty_feedback');
  } catch (error) {
    fallbackQc.qc_error = safeText(error?.message, String(error));
    fallbackQc.score_warnings = buildScoreWarnings(fallbackQc, qcScoreWarningThreshold);
    return fallbackQc;
  }
}

let metadataStatus = initialMetadataStatus;
let qcStatus = 'skipped';
let qcPayload = null;

try {
  if (shouldSendQcAction) {
    qcPayload = await resolveQcPayload();
    const headline = safeText(input.qc_action_headline, 'QC REVIEW');
    const lines = [
      '[' + headline + ']',
      'Session: ' + sessionToken,
      'Hook=' + String(qcPayload.hook_score ?? 'n/a') +
        ' | Clarity=' + String(qcPayload.clarity_score ?? 'n/a') +
        ' | Originality=' + String(qcPayload.originality_score ?? 'n/a') +
        ' | Practical=' + String(qcPayload.practical_value_score ?? 'n/a') +
        ' | Risk=' + String(qcPayload.risk_level ?? 'med'),
      'Feedback: ' + safeText(qcPayload.feedback, 'Can them feedback QC cu the.'),
    ];

    await sendTelegramMessage(lines.join('\n'));
    qcStatus = 'sent';
  }

  return {
    ...input,
    qc: qcPayload ?? input.qc,
    qc_status: qcPayload?.qc_status ?? input.qc_status,
    hook_score: qcPayload?.hook_score ?? asNumber(input.hook_score, null),
    clarity_score: qcPayload?.clarity_score ?? asNumber(input.clarity_score, null),
    originality_score: qcPayload?.originality_score ?? asNumber(input.originality_score, null),
    practical_value_score: qcPayload?.practical_value_score ?? asNumber(input.practical_value_score, null),
    risk_level: qcPayload?.risk_level ?? input.risk_level,
    feedback: qcPayload?.feedback ?? input.feedback,
    score_warnings: Array.isArray(qcPayload?.score_warnings) ? qcPayload.score_warnings : (Array.isArray(input.score_warnings) ? input.score_warnings : []),
    qc_action_notify_status: qcStatus,
    metadata_action_notify_status: metadataStatus,
  };
} catch (error) {
  return {
    ...input,
    qc_action_notify_status: shouldSendQcAction ? 'failed' : qcStatus,
    metadata_action_notify_status: metadataStatus,
    qc_action_notify_error: safeText(error?.message, String(error)).slice(0, 300),
  };
}
